    public record Point<T>(T X, T Y) where T : IAdditionOperators<T, T, T>
    {
        public static Point<T> operator +(Point<T> left, Translation<T> right) =>
        left with { X = left.X + right.XOffset, Y = left.Y + right.YOffset };
    }

